window.__QUIZ_DATA__=[{"id":"objective>Biology>2018>1","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"The scientist who introduced binomial nomenclature in the classification of organisms was","images":[],"options":{"A":"Charles Darwin","B":"Carolus Linnaeus","C":"John Ray","D":"Louis Pasteur"},"answer":"B","explanation":"The scientist who introduced binomial nomenclature in the classification of organisms was Carolus Linnaeus. Binomial nomenclature is a system of naming species of living things by giving each a name composed of two parts, both of which use Latin grammatical forms, although they can be based on words from other languages. The first part of the name identifies the genus to which the species belongs; the second part identifies the species within the genus. For example, humans belong to the genus Homo and within this genus to the species Homo sapiens.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>2","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Which of the following statement is true about arthropods?","images":[],"options":{"A":"Prothorax bears only legs","B":"Mesothorax bears only legs","C":"Metathorax bears only wings","D":"Prothorax bears only wings"},"answer":"A","explanation":"Arthropods are a group of invertebrate animals in the Phylum Arthropoda. They include insects, arachnids, myriapods, and crustaceans. These organisms have segmented bodies and jointed limbs, covered by a hard exoskeleton that must be periodically shed and renewed. In insects, which are a type of arthropods, the body is divided into three parts: head, thorax, and abdomen. The thorax itself is divided into three segments: prothorax, mesothorax, and metathorax. The prothorax is the first segment of the thorax, and it bears the first pair of legs. Therefore, the statement 'Prothorax bears only legs' is true about arthropods.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>3","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Which level of organization is spirogyra?","images":[],"options":{"A":"Organ system","B":"Organ","C":"Cell","D":"Tissue"},"answer":"C","explanation":"Spirogyra is a genus of filamentous green algae of the order Zygnematales. It is named for the helical or spiral arrangement of the chloroplasts that is characteristic of the species. It is commonly found in freshwater habitats, and there is no multicellular stage in its life cycle. It therefore exists at the cellular level of organization. An organism at the cellular level of organization is made up of cells, which are the basic units of life. In the case of Spirogyra, each filament is composed of end-to-end rows of cells. Therefore, the level of organization of Spirogyra is 'Cell'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>4","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The streaming movement of cytoplasm within paramecium is known as","images":[],"options":{"A":"transpiration","B":"digestion","C":"cyclosis","D":"osmosis"},"answer":"C","explanation":"The streaming movement of cytoplasm within cells, such as paramecium, is known as cyclosis. Cyclosis, also known as cytoplasmic streaming, is the directed flow of cytosol (the liquid component of the cytoplasm) and organelles around the cell. This movement aids in the delivery of nutrients, proteins, and organelles to all parts of the cell.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>5","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which of the following organelles is found only in plant?","images":[],"options":{"A":"Mitochondria","B":"Ribosomes","C":"Lysosomes","D":"Plastids"},"answer":"D","explanation":"Plastids are double-membrane organelle which are found in the cells of plants and algae. Plastids are responsible for manufacturing and storing of food. These often contain pigments that are used in photosynthesis and different types of pigments that can change the colour of the cell.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>6","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"Active transport differs from diffusion in that active transport","images":[],"options":{"A":"is a very fast process","B":"allows the movement of substances against concentration gradients","C":"takes place in both light and dark reactions of photosynthesis","D":"occurs in both plant and animal tissues"},"answer":"B","explanation":"Active transport is a process that moves molecules into cells even though they are moving against a concentration gradient. This is different from diffusion, which only moves molecules down a concentration gradient. Therefore, the correct answer is 'allows the movement of substances against concentration gradients'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>7","subject":"Biology","year":"2018","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagrams below are illustration of an experimental set-up to demonstrate a type of tropic response in plants. Study them and answer the questions below       The type of response demonstrated is","images":["data:image/png;base64,"],"options":{"A":"phototropism","B":"geotropism","C":"hydrotropism","D":"thigmotropism"},"answer":"C","explanation":"The plants tend to move near or towards the watered soil. Hydrotropism is a plant's growth response to water gradients in its environment. It is a type of tropism, which is the movement or growth of an organism in response to an external stimulus.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>8","subject":"Biology","year":"2018","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The diagrams below are illustration of an experimental set-up to demonstrate a type of tropic response in plants. Study them and answer the questions below     The conclusion drawn from the experiment is that","images":["data:image/png;base64,"],"options":{"A":"shoots of the plants are negatively thigmotropic","B":"shoots of plants are negatively geotropic","C":"leaves of plants are positively phototropic","D":"roots of plants are positively hydrotropic"},"answer":"D","explanation":"The root grows towards the source of water, i.e the root is positively hydrotropic and geotropic.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>9","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The odontoid process is found on the","images":[],"options":{"A":"axis vertebra","B":"atlas vertebra","C":"thoracic vertebra","D":"sacral vertebra"},"answer":"A","explanation":"The odontoid process, also known as the dens, is a protrusion of the C2 vertebra, also known as the axis. It is not found on the atlas, thoracic, or sacral vertebrae. Therefore, the correct answer is 'axis vertebra'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>10","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"A seedling was made to stand in solution of red ink for three hours and a transverse section of the stem was examined under the microscope. The process investigated was","images":[],"options":{"A":"the important of micro element to plants","B":"ascent of water through the xylem","C":"diffusion of coloured substances","D":"distribution of food in plants"},"answer":"B","explanation":"The process investigated in the question is the ascent of water through the xylem. This is a process in plants where water is transported from the roots to the rest of the plant, primarily through the xylem tissue. The red ink in the solution would have been drawn up through the xylem, demonstrating this process.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>11","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following structures would carry out respiration?","images":[],"options":{"A":"germinating cowpea","B":"decolorized leaf","C":"dry leaf","D":"boiled cowpea"},"answer":"A","explanation":"The structure that would carry out respiration among the options is a germinating cowpea. Respiration is a metabolic process that converts nutrients into energy in the presence of oxygen. A germinating seed, such as a cowpea, would be actively respiring as it uses stored nutrients to grow. The other options (decolorized leaf, dry leaf, boiled cowpea) are not capable of respiration. A decolorized leaf lacks chlorophyll and cannot photosynthesize or respire, a dry leaf is dead and therefore not metabolically active, and a boiled cowpea has been heat-treated, killing the seed and stopping all metabolic processes.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>12","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the following substances is not an excretory product of animals?","images":[],"options":{"A":"Carbon dioxide","B":"Urea","C":"Sweat","D":"Oxygen"},"answer":"D","explanation":"Excretion is the process by which metabolic waste is eliminated from an organism. In animals, the main excretory products are carbon dioxide, urea, and sweat. Oxygen is not an excretory product but rather a product of respiration that is used by the body for various metabolic processes.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>13","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"An example of homeostasis in living organisms is","images":[],"options":{"A":"cooling effect resulting from evaporation of water from the body surface.","B":"root hairs of a plant growing towards a source of light","C":"changing of the body colour of chameleon to match the colour of the foliage on which it is resting","D":"the release of phosphorus into the phloem of a plant growing in a phosphorus-deficient soil"},"answer":"A","explanation":"Homeostasis is the ability to maintain a constant internal environment in response to environmental changes. It is a unifying principle of biology. The nervous and endocrine systems control homeostasis in the body through feedback mechanisms involving various organs and organ systems","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>14","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Ultrafiltration in the kidney takes place in the","images":[],"options":{"A":"renal vein","B":"medulla","C":"loop of Henle","D":"bowman's capsule."},"answer":"D","explanation":"Ultrafiltration in the kidney takes place in the Bowman's capsule. Ultrafiltration is the process by which small molecules such as water, glucose, amino acids, and urea are filtered out of the blood and into the Bowman's capsule in the kidneys. This is the first step in the process of urine formation.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>15","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"The thyroid gland is located at the base of the","images":[],"options":{"A":"midbrain","B":"kidney","C":"neck","D":"liver"},"answer":"C","explanation":"The thyroid gland is located at the base of the neck. The thyroid gland is a butterfly-shaped organ located in the front of the neck, below the Adam's apple. It produces hormones that regulate the body's metabolic rate, heart and digestive function, muscle control, brain development and bone maintenance.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>16","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"Which of the following statements about the response of neurones to stimulus is correct?","images":[],"options":{"A":"Neurones respond to stimulus of any strength","B":"Neurones respond to all stimuli applied in rapid succession","C":"Neurones respond more rapidly during the absolute refractory period","D":"Intensity of stimulus must reach a threshold value before the neurones can be excited"},"answer":"D","explanation":"Neurons respond to stimuli only when the intensity of the stimulus reaches a certain threshold value. This is known as the 'all-or-none' principle. If the stimulus is below the threshold, the neuron will not fire. If the stimulus is at or above the threshold, the neuron will fire. This is why option 4 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>17","subject":"Biology","year":"2018","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Which of the following practice may lead to infection of the eye? Use of","images":[],"options":{"A":"contact lenses","B":"convex lenses","C":"biconcave lenses","D":"concave lenses"},"answer":"A","explanation":"The use of contact lenses can lead to eye infections if they are not properly cleaned and cared for. Bacteria, fungi, and other microorganisms can grow on the lenses and cause infections. This is not the case with convex, biconcave, or concave lenses, as they do not come into direct contact with the eye. Therefore, option 1 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>18","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The structures for gaseous exchange in breathing root are","images":[],"options":{"A":"stomata","B":"lenticels","C":"cuticle","D":"mitochondria"},"answer":"B","explanation":"The structures for gaseous exchange in breathing roots are lenticels. Lenticels are small pores in the bark of stems and roots of woody plants that allow gas exchange between the atmosphere and the internal tissues. They are not stomata, which are found on leaves, nor cuticle, which is a waxy layer on the surface of plants, nor mitochondria, which are organelles within cells.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>19","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES","question":"The diagram below is an illustration of the life cycle of an insect. Study it and answer questions 19 and 20.       The adult insect in this life cycle is","images":["data:image/png;base64,"],"options":{"A":"housefly","B":"butterfly","C":"cockroach","D":"mosquito"},"answer":"B","explanation":"Butterfly has a caterpillar as its larvae and its pupa wrapped up in a silk.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>20","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES","question":"The diagram below is an illustration of the life cycle of an insect. Study it and answer questions 19 and 20.     The larva is also known as","images":["data:image/png;base64,"],"options":{"A":"nymph","B":"maggot","C":"caterpillar","D":"chrysalis"},"answer":"C","explanation":"Caterpillar: This is the larval stage of butterflies and moths. Caterpillars are typically terrestrial, have a segmented body, and possess legs. They are known for their role in consuming large amounts of plant material before pupating and transforming into their adult forms.    Larva: This is the juvenile form of various animals that undergo metamorphosis, including insects like mosquitoes. Mosquito larvae, often called \"wrigglers,\" live in water and have a distinct appearance, different from their adult form. They do not have legs and move by wriggling through the water.    Note: A larva is not the same as a caterpillar in mosquitoes.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>21","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"The source of energy required by plants during food production is","images":[],"options":{"A":"photosynthesis","B":"chlorophyll","C":"sunlight","D":"microorganisms"},"answer":"C","explanation":"The source of energy required by plants during food production is sunlight. This process is called photosynthesis, where plants convert sunlight, carbon dioxide, and water into glucose (food) and oxygen. Chlorophyll is the pigment in plants that absorbs sunlight and is crucial for photosynthesis, but it is not the source of energy. Microorganisms are not involved in this process.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>22","subject":"Biology","year":"2018","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"One major difference between plant and animal nutrition is the ability of plants to synthesize","images":[],"options":{"A":"food for plants and animals","B":"water for plants","C":"water for animals","D":"food for plants only"},"answer":"A","explanation":"The major difference between plant and animal nutrition is the ability of plants to synthesize food for both plants and animals. Plants, being autotrophs, can synthesize their own food through the process of photosynthesis. Animals, being heterotrophs, cannot synthesize their own food and depend on plants or other animals for their nutrition.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>23","subject":"Biology","year":"2018","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"By what process is starch converted into maltose","images":[],"options":{"A":"hydrolysis","B":"condensation","C":"translocation","D":"photosynthesis"},"answer":"A","explanation":"Starch is converted into maltose through the process of hydrolysis. Hydrolysis is a chemical reaction in which water is used to break down a compound. In this case, water is used to break down the starch molecule into maltose. Therefore, the correct answer is 'hydrolysis'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>24","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"The ascent of water in tall tree is mainly due to","images":[],"options":{"A":"adhesive forces","B":"transpiration pull","C":"root pressure","D":"cohesive forces"},"answer":"B","explanation":"The ascent of water in tall trees is mainly due to the transpiration pull. Transpiration pull is the main mechanism of water movement in plants. When water evaporates from the leaves, a negative pressure (or suction) is created that pulls water from the roots and up the stem in the xylem. This process is facilitated by the cohesive and adhesive properties of water.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>25","subject":"Biology","year":"2018","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"The duodenum of a person was surgically removed. Which of the following food substances would have their digestion affected?","images":[],"options":{"A":"Starch and protein only","B":"Starch and lipids","C":"Starch,peptones and maltose","D":"Starch, protein and lipids"},"answer":"D","explanation":"The duodenum is the first part of the small intestine immediately beyond the stomach, leading to the jejunum. It is the primary site for the digestion of food in the small intestine. It receives gastric chyme from the stomach, together with digestive juices from the pancreas (digestive enzymes) and the liver (bile). Enzymes break down proteins into peptones and proteoses, fats into fatty acids and glycerol, and carbohydrates into simple sugars like glucose, fructose, etc. Therefore, if the duodenum of a person was surgically removed, the digestion of starch, protein, and lipids would be affected.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>26","subject":"Biology","year":"2018","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Which of the following dental formulae represents the dentition in rabbits?","images":[],"options":{"A":"I 2\u22151 C 0\u22150 P 2\u22152 M 3\u22153","B":"I 2\u22152 C 1\u22152 P 2\u22152 M 3\u22153","C":"I 1\u22152 C 0\u22150 P 2\u22153 M 3\u22153","D":"I 2\u22151 C 0\u22151 P 1\u22152 M 3\u22153"},"answer":"A","explanation":"In rabbits, the dental formula should be:  I 2/1, C 0/0, P 3/2, M 3/3    This means:  Incisors (I): Rabbits have 2 upper and 1 lower incisor on each side.   Canines (C): Rabbits do not have canine teeth.  Premolars (P): Rabbits have 3 upper and 2 lower premolars on each side.  Molars (M): Rabbits have 3 upper and 3 lower molars on each side.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>27","subject":"Biology","year":"2018","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The diagram below is an illustration of an experimental set-up to demonstrate a property of soil. Study it and answer questions 27 and 28.       The property of soil demonstrated is","images":["data:image/png;base64,"],"options":{"A":"particle size","B":"capillarity","C":"colour","D":"texture"},"answer":"B","explanation":"It is to determine the rate at which the soils absorb water, i.e, to know the level to which water has risen in each of the tubes. The water in this case, is known as capillarity water.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>28","subject":"Biology","year":"2018","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The diagram below is an illustration of an experimental set-up to demonstrate a property of soil. Study it and answer questions 27 and 28.     Which of the following statements would be a correct observation at the end of the experiment? Water moves","images":["data:image/png;base64,"],"options":{"A":"highest in sandy soil","B":"lowest in loamy soil","C":"to the same level in all soil types","D":"highest in clayey soil"},"answer":"D","explanation":"Sandy soil:  Larger particles and pores reduce capillary rise.  Loamy soil: Capillary rise varies based on soil composition; not necessarily lowest.  Same level in all soils: Capillary rise differs due to soil texture and pore size.  Clayey soil: Smaller particles and pores enhance capillary rise, making it highest.    Therefore, highest in clayey soil is correct because fine particles and small pores in clayey soil promote stronger capillary action compared to sandy or loamy soils","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>29","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"The most important factor(s) that influence(s) the ecological niche of an organism is/are the","images":[],"options":{"A":"water, light and predator-prey relationship","B":"food and water availability","C":"physical environment","D":"competition for food and space"},"answer":"D","explanation":"The most important factor(s) that influence(s) the ecological niche of an organism is/are competition for food and space.    Ecological niche refers to the role and position of an organism within its environment, including how it obtains food, shelter, and interacts with other species. Competition for resources like food and space is a critical factor that shapes the niche of an organism, influencing its survival and reproduction strategies","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>30","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The diagram below is an illustration of organisms in an air-tight aquarium. The most important factor needed by the organisms is","images":["data:image/png;base64,"],"options":{"A":"light energy","B":"low humidity","C":"oxygen","D":"nitrate"},"answer":"C","explanation":"Since the aquarium is air-tight, there is a low possibility of having dissolved oxygen in it.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>31","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"Which of the following instruments is used to determine the turbidity of water?","images":[],"options":{"A":"Hygrometer","B":"Hydrometer","C":"Secchi disc","D":"Rain gauge"},"answer":"C","explanation":"A Secchi disc is used to measure water transparency or turbidity in bodies of water. It is a circular disc, divided into quarters of alternating black and white color, which is lowered into the water until it can no longer be seen; the depth it reaches before disappearing is known as the Secchi depth, which gives a measure of the transparency or turbidity of the water.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>32","subject":"Biology","year":"2018","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"In an ecosystem, the least efficient energy transfer link is from the","images":[],"options":{"A":"secondary consumers to decomposers","B":"sun to producers","C":"primary consumers to secondary consumers","D":"producer to primary consumers"},"answer":"A","explanation":"In ecosystems, energy is transferred through trophic levels, starting from producers (plants) to primary consumers (herbivores), then to secondary consumers (carnivores), and so on. The efficiency of energy transfer decreases as you move up the trophic levels.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>33","subject":"Biology","year":"2018","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Xerophytes have the following characteristics aimed at conserving water except","images":[],"options":{"A":"thick cuticle","B":"broad leaf surfaces","C":"sunken stomata","D":"waxy cuticle"},"answer":"B","explanation":"Xerophytes are plants that are adapted to survive in dry environments with little water. They have several adaptations to conserve water, such as a thick cuticle, sunken stomata, and a waxy cuticle. However, they do not have broad leaf surfaces. Broad leaf surfaces would increase the surface area for evaporation, which would lead to more water loss. Therefore, xerophytes typically have small, narrow leaves or no leaves at all to minimize water loss.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>34","subject":"Biology","year":"2018","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : BIOLOGICAL ASSOCIATIONS","question":"An association between living organisms in which one lives on and feeds at the expense of the other is known as","images":[],"options":{"A":"commensalism","B":"predation","C":"parasitism","D":"mutualism"},"answer":"C","explanation":"The association between living organisms in which one lives on and feeds at the expense of the other is known as parasitism. In this relationship, the parasite benefits while the host is harmed. Commensalism is a relationship where one organism benefits and the other is neither harmed nor benefited. Predation is where one organism kills and eats another. Mutualism is a relationship where both organisms benefit.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>35","subject":"Biology","year":"2018","type":"Objective","topic":"ECOLOGY OF POPULATION : FACTORS THAT AFFECT POPULATION","question":"When large numbers of organisms share limited space and resources, the immediate result is","images":[],"options":{"A":"extinction","B":"emigration","C":"competition","D":"immigration"},"answer":"C","explanation":"When large numbers of organisms share limited space and resources, the immediate result is competition. This is because all organisms need certain resources to survive and reproduce. If these resources are limited, organisms will compete with each other to obtain them. This is a fundamental concept in ecology known as the 'competitive exclusion principle', which states that two species competing for the same resources cannot coexist at constant population values.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>36","subject":"Biology","year":"2018","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Which of the following diseases is caused by a bacterium?","images":[],"options":{"A":"Ringworm","B":"Poliomyelitis","C":"Syphilis","D":"Malaria"},"answer":"C","explanation":"Syphilis is caused by a bacterium called Treponema pallidum. Bacteria are single-celled organisms that can cause a variety of diseases in humans, including syphilis. The other diseases listed in the options (Ringworm, Poliomyelitis, and Malaria) are caused by fungi, viruses, and parasites, respectively, not bacteria.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>37","subject":"Biology","year":"2018","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Conservation of wildlife is necessary mainly because","images":[],"options":{"A":"wild species cannot resist diseases better than their domesticated species","B":"many predator wild animals help in the control of pests","C":"it prevents the extinction of species","D":"many people derive pleasure from observing wild animals"},"answer":"C","explanation":"Conservation of wildlife is primarily necessary to prevent the extinction of species. This is because every species plays a unique role in the balance of nature. The extinction of a single species can have a ripple effect on the ecosystem, leading to the imbalance of the ecosystem. Therefore, conservation efforts are necessary to maintain biodiversity and the health of the ecosystem.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>38","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"Two unconscious patient X and Y whose blood group genotypes are AO and AB respectively were transfused with blood from the same donor. Patient X immediately showed signs of difficulty in breathing while patient Y showed no negative reaction.  Use the information above to answer the question below    Patients X and Y were likely transfused with blood of genotype","images":[],"options":{"A":"OO","B":"AO","C":"BO","D":"AA"},"answer":"C","explanation":"In the given scenario, patient X has blood group genotype AO and patient Y has blood group genotype AB. Patient X showed signs of difficulty in breathing after the transfusion, which indicates a negative reaction to the transfused blood. This reaction could be due to the presence of B antigens in the transfused blood, which are not compatible with patient X's blood group. On the other hand, patient Y, who has blood group AB, did not show any negative reaction because blood group AB can receive blood from any group (A, B, AB, or O). Therefore, the blood transfused was likely of genotype BO.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2018>39","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"Two unconscious patient X and Y whose blood group genotypes are AO and AB respectively were transfused with blood from the same donor. Patient X immediately showed signs of difficulty in breathing while patient Y showed no negative reaction.  Use the information above to answer the question below  What should the hospital have done to prevent patient X from showing the symptom described above? patient X should have","images":[],"options":{"A":"undergo an agglutination test","B":"been asked for the blood group","C":"been screened for HIV","D":"undergone malaria test"},"answer":"A","explanation":"The hospital should have performed an agglutination test on patient X. An agglutination test is a test that is used to determine blood type by mixing blood with antibodies that cause the blood cells to clump together if the antibodies are specific for the individual's blood type. In this case, if patient X's blood had been tested, it would have been found that the blood from the donor was not compatible, and the adverse reaction could have been avoided.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>40","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"The greatest contribution to genetic studies was made by","images":[],"options":{"A":"Gregor Mendel","B":"Thomas Morgan","C":"Charles Darwin","D":"Robert Hooke"},"answer":"A","explanation":"The greatest contribution to genetic studies was made by Gregor Mendel. Mendel's experiments with pea plants established many of the rules of heredity, now referred to as the laws of Mendelian inheritance. His work laid the foundation for the study of genetics.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>41","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"The exchange of genes between homologous chromosome is called","images":[],"options":{"A":"crossing over","B":"back cross","C":"test cross","D":"mutation"},"answer":"A","explanation":"Crossing over is when genes from one chromosome (e.g paternal A, B, C) swap with genes from the other chromosome (maternal a, b, c) leading to a new gene combination in the resulting chromatids","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>42","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"The diagram below are illustration of the inheritance of coat colour in mice. J, K, L, M and  N are parents. The cross between two parent mice gave rise to offspring P, Q, R and S. Study the diagrams and answer the question below.       Which parent mouse is heterozygous for coat color?","images":["data:image/png;base64,"],"options":{"A":"M","B":"J","C":"K","D":"L"},"answer":"D","explanation":"Mouse L is heterozygous for coat colour, because it contains two different characters, which are white and black.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>43","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"The diagram below are illustration of the inheritance of coat colour in mice. J, K, L, M and  N are parents. The cross between two parent mice gave rise to offspring P, Q, R and S. Study the diagrams and answer the question below.     Which of the offspring are all homozygous?","images":["data:image/png;base64,"],"options":{"A":"P","B":"Q","C":"S","D":"R"},"answer":"C","explanation":"The offspring of S are all homozygous which is gotten from the parent.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>44","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS","question":"Genes that remain linked are those","images":[],"options":{"A":"close to each other on the chromosome","B":"on the same locus on the chromosome","C":"on the homologous chromosome","D":"which are allelic pair"},"answer":"A","explanation":"Genes that remain linked are those 'close to each other on the chromosome'. This is because during crossing over, the closer two genes are on a chromosome, the less likely they are to be separated. This is known as genetic linkage.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>45","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"A plant cell has 14 chromosomes prior to mitosis. what is the number of chromosome in the daughter cells?","images":[],"options":{"A":"14","B":"56","C":"28","D":"7"},"answer":"A","explanation":"Mitosis is a type of cell division that results in two daughter cells each having the same number and kind of chromosomes as the parent nucleus, typical of ordinary tissue growth. Therefore, if a plant cell has 14 chromosomes prior to mitosis, each daughter cell will also have 14 chromosomes.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>46","subject":"Biology","year":"2018","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"The chemical bond that holds the bases of the two strands of DNA together is","images":[],"options":{"A":"oxygen bond","B":"hydrogen bond","C":"electrovalent bond","D":"covalent bond"},"answer":"B","explanation":"The two strands of DNA are held together by hydrogen bonds. These bonds occur between the bases of the two strands. Each base forms a hydrogen bond with a base on the opposite strand: Adenine pairs with Thymine, and Guanine pairs with Cytosine.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>47","subject":"Biology","year":"2018","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"The diagram below is an illustration of one of the theories of evolution. Study it and answer the question below      Who proposed the theory in the illustration?","images":["data:image/jpeg;base64,"],"options":{"A":"Louis Pasteur","B":"Gregor Mendel","C":"Robert Hook","D":"Jean Lamarck"},"answer":"D","explanation":"This is the theory of use and disuse of body parts.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2018>48","subject":"Biology","year":"2018","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"The diagram below is an illustration of one of the theories of evolution. Study it and answer the question below    The theory supports","images":["data:image/jpeg;base64,"],"options":{"A":"struggle for survival","B":"natural selection","C":"independent assortment","D":"the use and disuse of body parts"},"answer":"D","explanation":"Jean Larmack explained the theory of use and disuse of body parts using giraffes as it illustration specimen.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>49","subject":"Biology","year":"2018","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"In evolution, fossils are naturally preserved in","images":[],"options":{"A":"rocks","B":"water","C":"chemicals","D":"trees"},"answer":"A","explanation":"Fossils are naturally preserved in rocks. Fossils are the remains or traces of plants and animals that lived in the past. Over time, layers of sediment build up and harden into rock, preserving the shape of the organisms. This process is known as fossilization and the resulting preserved remains are called fossils. Therefore, the correct answer is rocks.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2018>50","subject":"Biology","year":"2018","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following insects is not a social insect?","images":[],"options":{"A":"Termite","B":"Housefly","C":"Honeybee","D":"Ant"},"answer":"B","explanation":"Social insects are those species of insects that live in colonies and have a division of labor among the different types of individuals (castes). These include ants, bees, wasps, and termites. Houseflies, on the other hand, do not live in colonies and do not have a division of labor among individuals. Therefore, the housefly is not a social insect.","marks":"1","difficulty":"1"}];